const detectPII = (data: any): boolean => {
  const piiPatterns = [
    /\b\d{3}-\d{2}-\d{4}\b/g, // SSN
    /\b4[0-9]{12}(?:[0-9]{3})?\b/g, // Visa
    /\b(?:[A-Z][A-Z ]{0,19}[A-Z])\d{9}\b/g, // API Keys
    /(?=^.{6,}$)(([a-zA-Z0-9$&+,:;=?@#|'<>.^*()%!-]){1,}|\S{1,})/g // Passwords
  ];

  const text = JSON.stringify(data);
  return piiPatterns.some(pattern => pattern.test(text));
};

// n8n Code Node after AI Agent
const items = $input.all();
for (const item of items) {
  if (detectPII(item.json)) {
    throw new Error('PII detected in AI Agent output: ' + JSON.stringify(item.json));
  }
}
return items;

const traceCredentials = (items: any[]): string[] => {
  const credPatterns = [/secret[A-Za-z0-9_-]{8,}/gi, /api[-_]?key[A-Za-z0-9_-]{16,}/gi];
  const leaked = [];

  items.forEach((item, index) => {
    const nodeName = $workflow.nodes[index]?.name || 'unknown';
    const data = JSON.stringify(item.json);
    credPatterns.forEach(pattern => {
      const matches = data.match(pattern);
      if (matches) {
        leaked.push(`${nodeName}: ${matches.join(', ')}`);
      }
    });
  });
  return leaked;
};

const leaks = traceCredentials($input.all());
if (leaks.length > 0) {
  console.error('Credential leaks detected:', leaks);
  return [{ json: { alert: 'CREDENTIAL_LEAK', details: leaks } }];
}
return $input.all();

interface MemoryLeak {
  sessionId: string;
  leakedData: string[];
  ageDays: number;
}

const scanMemory = (memoryItems: any[]): MemoryLeak[] => {
  const leaks: MemoryLeak[] = [];
  const SENSITIVE_PATTERNS = [
    { pattern: /\b\d{16}\b/g, type: 'CARD_NUMBER' },
    { pattern: /xoxb-[0-9]{10,}/g, type: 'SLACK_TOKEN' }
  ];

  memoryItems.forEach(item => {
    const sessionId = item.json.sessionId;
    const context = item.json.memoryContext || '';
    const ageDays = (Date.now() - new Date(item.json.timestamp).getTime()) / (1000 * 60 * 60 * 24);

    SENSITIVE_PATTERNS.forEach(({ pattern, type }) => {
      const matches = context.match(pattern);
      if (matches && ageDays > 7) {
        leaks.push({ sessionId, leakedData: matches, ageDays: Math.floor(ageDays) });
      }
    });
  });
  return leaks;
};

const leaks = scanMemory($input.all());
if (leaks.length > 0) {
  throw new Error(`Stale memory leaks: ${JSON.stringify(leaks)}`);
}
return $input.all();

