const redactPII = (text: string): string => {
  const redactions = [
    { pattern: /\b\d{3}-\d{2}-\d{4}\b/g, replacement: '[SSN_REDACTED]' },
    { pattern: /\b4[0-9]{12}(?:[0-9]{3})?\b/g, replacement: '[CARD_REDACTED]' },
    { pattern: /(?=^.{6,}$)(([a-zA-Z0-9$&+,:;=?@#|'<>.^*()%!-]){1,}|\S{1,})/g, replacement: '[PASSWORD_REDACTED]' }
  ];

  return redactions.reduce((cleaned, { pattern, replacement }) => {
    return cleaned.replace(pattern, replacement);
  }, text);
};

const items = $input.all();
const cleanedItems = items.map(item => {
  const cleanedJson = JSON.parse(redactPII(JSON.stringify(item.json)));
  return { json: cleanedJson };
});

return cleanedItems;

interface SafeToolParams {
  [key: string]: string | number | boolean;
}

const sanitizeToolParams = (params: any): SafeToolParams => {
  const safeParams: SafeToolParams = {};
  const BLOCKED_PATTERNS = [/secret[A-Za-z0-9_-]{8,}/gi, /\bkey[:=][\s\"']*[A-Za-z0-9_-]{16,}/gi];

  Object.entries(params).forEach(([key, value]) => {
    const strValue = String(value);
    const hasSecrets = BLOCKED_PATTERNS.some(pattern => pattern.test(strValue));

    if (!hasSecrets) {
      safeParams[key] = ['string', 'number', 'boolean'].includes(typeof value) ? value : '[SANITIZED]';
    } else {
      safeParams[key] = '[CREDENTIAL_BLOCKED]';
      console.warn(`Blocked secret in tool param ${key}: ${strValue.substring(0, 20)}...`);
    }
  });

  return safeParams;
};

const safeParams = sanitizeToolParams($json.toolParams);
return [{ json: { safeParams, originalParamsBlocked: Object.keys($json.toolParams).length !== Object.keys(safeParams).length } }];

const filterSafeMemory = (memoryItems: any[]) => {
  const MAX_AGE_HOURS = 24;
  const SAFE_PATTERNS = [/email/i, /name/i, /message/i];

  return memoryItems.filter(item => {
    const ageHours = (Date.now() - new Date(item.json.timestamp).getTime()) / (1000 * 60 * 60);
    const context = item.json.memoryContext || '';

    // Block if too old OR contains dangerous patterns
    const isTooOld = ageHours > MAX_AGE_HOURS;
    const hasDangerousData = !SAFE_PATTERNS.some(pattern => pattern.test(context));

    if (isTooOld) {
      console.log(`Blocked stale memory: ${ageHours.toFixed(1)}h old`);
    }

    return !(isTooOld || hasDangerousData);
  });
};

const safeMemory = filterSafeMemory($input.all());
return safeMemory.length > 0 ? safeMemory : [{ json: { message: 'No safe memory context available' } }];

