import { Vex } from '@vex_dev/sdk';

const vex = new Vex({
  apiKey: $secrets.VEX_API_KEY,
  framework: 'n8n',
  workflowId: $execution.id
});

const result = await vex.scan({
  nodeType: 'n8n-ai-agent',
  inputData: $json, 
  executionContext: {
    workflowName: $workflow.name,
    nodeName: $node.name,
    timestamp: new Date().toISOString()
  },
  rules: ['pii-detection', 'credential-leak', 'memory-injection']
});

if (result.blocked) {
  // Auto-insert redaction node
  await vex.remediate({
    action: 'insert-redaction',
    position: 'post-ai-agent',
    workflowId: $execution.id
  });

  return [{ 
    json: { 
      vexBlocked: true, 
      leakedData: result.matches,
      remediation: result.fixCode 
    } 
  }];
}

// Forward safe data
return [{ json: { vexStatus: 'clean', data: $json } }];
